const { ethers } = require('ethers');

async function initialize(providerUrl, privateKey, erc20Address, dexContractAddress) {
    const provider = new ethers.providers.JsonRpcProvider(providerUrl);
    const wallet = new ethers.Wallet(privateKey, provider);

    const erc20Abi = [
        "function approve(address _spender, uint256 _value) public returns (bool)",
        "function balanceOf(address _owner) public view returns (uint256)"
    ];
    const dexAbi = [
        "function swap(address _fromToken, address _toToken, uint256 _amount) external"
    ];

    const tokenContract = new ethers.Contract(erc20Address, erc20Abi, wallet);
    const dexContract = new ethers.Contract(dexContractAddress, dexAbi, wallet);

    return { wallet, tokenContract, dexContract };
}

async function approveMax(tokenContract, dexContractAddress) {
    const maxUint256 = ethers.constants.MaxUint256;
    const approveTx = await tokenContract.approve(dexContractAddress, maxUint256);
    await approveTx.wait();
    console.log(`Max approval transaction hash: ${approveTx.hash}`);
}

async function swapTokens(dexContract, fromToken, toToken, amount) {
    const swapTx = await dexContract.swap(fromToken, toToken, amount);
    await swapTx.wait();
    console.log(`Swap transaction hash: ${swapTx.hash}`);
}

